  "calcium","iron","zinc","niacin","riboflavin","thiamine","lecithin","gum","citric",
  "vanilla","cinnamon","pepper","turmeric","cardamom","ginger","garlic","onion",
  "tomato","cheese","whey","casein","gelatin","pectin","carrageenan","inulin",
